```tsx title="src/App.tsx"
const metrics = [
  {
    "label": "Export mode",
    "value": "SVG -> PNG"
  },
  {
    "label": "Scale choices",
    "value": "1x / 2x / 4x"
  },
  {
    "label": "Square mode",
    "value": "Crop + padding"
  },
  {
    "label": "Privacy",
    "value": "Client-only"
  }
] as const;
const cards = [
  {
    "meta": "Upload",
    "title": "Drag-and-drop upload",
    "body": "Accept SVG or raster images and keep the file in-browser for fast local conversion."
  },
  {
    "meta": "SVG to PNG export",
    "title": "High-resolution output",
    "body": "Choose a scale preset before export so icons and social images are crisp."
  },
  {
    "meta": "Square controls",
    "title": "Crop or pad",
    "body": "Make uploaded images square with either centered crop or safe background padding."
  },
  {
    "meta": "Preview",
    "title": "Before download",
    "body": "Show the current canvas dimensions, transparency choice, and expected file size."
  },
  {
    "meta": "Download",
    "title": "Two-click finish",
    "body": "The primary action prepares the PNG and exposes a clear Download action."
  },
  {
    "meta": "No server",
    "title": "Private by default",
    "body": "The utility does not need uploads to a backend to be useful in the first version."
  }
] as const;
const actions = [
  "SVG to PNG export",
  "Make square",
  "Download"
] as const;

export default function App() {
  return (
    <main className="shell">
      <section className="hero">
        <p className="eyebrow">Client-only image utility</p>
        <h1>SVG to PNG Studio</h1>
        <p className="lede">A browser-only conversion tool for drag-and-drop upload, high-resolution SVG to PNG export, scale presets, square crop/padding controls, and one-click Download.</p>
        <div className="metrics">
          {metrics.map((metric) => (
            <article key={metric.label} className="metric">
              <span>{metric.label}</span>
              <strong>{metric.value}</strong>
            </article>
          ))}
        </div>
      </section>

      <section className="dropzone">
        <label htmlFor="asset-upload">Drag-and-drop upload</label>
        <input id="asset-upload" type="file" accept="image/*,.svg" />
        <div className="control-row">
          <button type="button">SVG to PNG export</button>
          <button type="button">2x scale</button>
          <button type="button">4x scale</button>
          <button type="button">Square crop</button>
          <button type="button">Square padding</button>
          <button type="button">Download</button>
        </div>
      </section>

      <section className="grid">
        {cards.map((card) => (
          <article key={card.title} className="card">
            <span>{card.meta}</span>
            <h2>{card.title}</h2>
            <p>{card.body}</p>
          </article>
        ))}
      </section>

      <section className="actions">
        <h2>Action loop</h2>
        {actions.map((action) => <button key={action} type="button">{action}</button>)}
      </section>
    </main>
  );
}
```

