const metrics = [
  {
    "label": "Split-brain risk",
    "value": "High"
  },
  {
    "label": "Checkout flow",
    "value": "Mapped"
  },
  {
    "label": "Webhook events",
    "value": "Queued"
  },
  {
    "label": "KV sync",
    "value": "Single function"
  }
] as const;
const cards = [
  {
    "meta": "split-brain",
    "title": "Provider vs database state",
    "body": "The app must treat payment provider state and internal database state as separate systems that can drift."
  },
  {
    "meta": "checkout",
    "title": "Checkout flow",
    "body": "Create checkout, bind the customer, return to the app, and never assume success until webhook confirmation."
  },
  {
    "meta": "customer binding",
    "title": "Stable customer identity",
    "body": "Store the provider customer id next to the app user id before subscriptions become complicated."
  },
  {
    "meta": "webhook",
    "title": "Webhook event ledger",
    "body": "Persist processed event ids so retries are idempotent and visible."
  },
  {
    "meta": "sync",
    "title": "customer-sync-to-KV",
    "body": "One customer-sync-to-KV function writes the minimal billing snapshot used by the product."
  },
  {
    "meta": "developer responsibility",
    "title": "What still belongs to you",
    "body": "You still own auth, entitlement checks, retry policy, audit logs, and product-specific access rules."
  }
] as const;
const actions = [
  "Run checkout",
  "Replay webhook",
  "Sync customer to KV",
  "Review responsibility checklist"
] as const;

export default function App() {
  return (
    <main className="shell">
      <section className="hero">
        <p className="eyebrow">SaaS payments implementation</p>
        <h1>Payments Sanity Playbook</h1>
        <p className="lede">A developer-facing payments guide that explains the split-brain problem between payment provider state and app database state, then shows checkout, customer binding, webhook handling, and customer-sync-to-KV.</p>
        <div className="metrics">
          {metrics.map((metric) => (
            <article key={metric.label} className="metric">
              <span>{metric.label}</span>
              <strong>{metric.value}</strong>
            </article>
          ))}
        </div>
      </section>


      <section className="grid">
        {cards.map((card) => (
          <article key={card.title} className="card">
            <span>{card.meta}</span>
            <h2>{card.title}</h2>
            <p>{card.body}</p>
          </article>
        ))}
      </section>

      <section className="actions">
        <h2>Action loop</h2>
        {actions.map((action) => <button key={action} type="button">{action}</button>)}
      </section>
    </main>
  );
}
