  },
  {
    "meta": "math-heavy",
    "title": "CPU pressure test",
    "body": "Math-heavy rendering highlights compute variance, not just happy-path latency."
  },
  {
    "meta": "variability",
    "title": "Mean/min/max table",
    "body": "The dashboard explains that API/database work is often the real bottleneck after SSR differences."
  }
] as const;
const actions = [
  "Compare Cloudflare",
  "Compare Vercel",
  "Show winner badges",
  "Inspect variability"
] as const;

export default function App() {
  return (
    <main className="shell">
      <section className="hero">
        <p className="eyebrow">100-iteration rendering comparison</p>
        <h1>SSR Platform Benchmark</h1>
        <p className="lede">A benchmark dashboard comparing Cloudflare and Vercel across Next.js, React SSR, SvelteKit, vanilla rendering, and math-heavy tests, with mean/min/max/variability tables and winner badges.</p>
        <div className="metrics">
          {metrics.map((metric) => (
            <article key={metric.label} className="metric">
              <span>{metric.label}</span>
              <strong>{metric.value}</strong>
            </article>
          ))}
        </div>
      </section>


      <section className="grid">
        {cards.map((card) => (
          <article key={card.title} className="card">
            <span>{card.meta}</span>
            <h2>{card.title}</h2>
            <p>{card.body}</p>
          </article>
        ))}
      </section>

      <section className="actions">
        <h2>Action loop</h2>
        {actions.map((action) => <button key={action} type="button">{action}</button>)}
      </section>
    </main>
  );
}
