const metrics = [
  {
    "label": "Ruby on Rails",
    "value": "Fast CRUD"
  },
  {
    "label": "Elixir Phoenix",
    "value": "Realtime"
  },
  {
    "label": "GraphQL",
    "value": "Go API + SPA"
  },
  {
    "label": "T3 / RSC",
    "value": "Typed React"
  }
] as const;
const cards = [
  {
    "meta": "Ruby on Rails",
    "title": "Convention lane",
    "body": "Rails wins when server-rendered CRUD speed and integrated defaults matter most."
  },
  {
    "meta": "Elixir Phoenix",
    "title": "Realtime lane",
    "body": "Phoenix makes live updates and fault tolerance a first-class tradeoff."
  },
  {
    "meta": "Go + GraphQL + React SPA",
    "title": "Service split lane",
    "body": "Go plus GraphQL plus React SPA separates backend performance from frontend iteration."
  },
  {
    "meta": "T3",
    "title": "Classic Next.js/T3 stack",
    "body": "T3 emphasizes type-safe full-stack React with familiar deployment ergonomics."
  },
  {
    "meta": "RSC",
    "title": "Next.js app-router/RSC",
    "body": "App Router and RSC shift more work to the server component boundary."
  },
  {
    "meta": "line of code",
    "title": "Tradeoff matrix",
    "body": "Line of code comparison, mock deployment links, and tradeoff matrix make the differences visible."
  }
] as const;
const actions = [
  "Open tradeoff matrix",
  "Compare line of code",
  "View deployment links"
] as const;

export default function App() {
  return (
    <main className="shell">
      <section className="hero">
        <p className="eyebrow">Implementation comparison explorer</p>
        <h1>One App, Five Stacks</h1>
        <p className="lede">A comparison explorer for the same product built in Ruby on Rails, Elixir Phoenix, Go plus GraphQL plus React SPA, classic Next.js/T3 stack, and Next.js app-router/RSC.</p>
        <div className="metrics">
          {metrics.map((metric) => (
            <article key={metric.label} className="metric">
              <span>{metric.label}</span>
              <strong>{metric.value}</strong>
            </article>
          ))}
        </div>
      </section>


      <section className="grid">
        {cards.map((card) => (
          <article key={card.title} className="card">
            <span>{card.meta}</span>
            <h2>{card.title}</h2>
            <p>{card.body}</p>
          </article>
        ))}
      </section>

      <section className="actions">
        <h2>Action loop</h2>
        {actions.map((action) => <button key={action} type="button">{action}</button>)}
      </section>
    </main>
  );
}

